                </form>
            </div>
        </div>
    );
};

const ResultsEditorModal: React.FC<{
    student: User;
    onClose: () => void;
}> = ({ student, onClose }) => {
    const [semester, setSemester] = useState(1);
    const [result, setResult] = useState<SBTETResult | null>(null);
    const [isSaving, setIsSaving] = useState(false);
    const [loading, setLoading] = useState(false);

    const fetchResult = async () => {
        setLoading(true);
        const allResults = await getAllSbtetResultsForPin(student.pin);
        const existingResult = allResults.find(r => r.semester === semester);
        if (existingResult) {
            setResult(existingResult);
        } else {
            // Create default skeleton
            setResult({
                id: `res-${student.pin}-${semester}`,
                pin: student.pin,
                semester,
                subjects: [
                    { code: 'SUB-01', name: '', mid1: 0, mid2: 0, internal: 0, external: 0, total: 0, credits: 0 }
                ],
                totalMarks: 0,
                creditsEarned: 0,
                sgpa: 0,
                status: 'Fail'
            });
        }
        setLoading(false);
    };

    useEffect(() => {
        fetchResult();
    }, [semester, student.pin]);

    const handleSubjectChange = (index: number, field: string, value: any) => {
        if (!result) return;
        const newSubjects = [...result.subjects];

        // Ensure values don't exceed max marks
        let sanitizedValue = Number(value);
        if (field === 'mid1' || field === 'mid2' || field === 'internal') {
            if (sanitizedValue > 20) sanitizedValue = 20;
        } else if (field === 'external') {
            if (sanitizedValue > 40) sanitizedValue = 40;
        }

        newSubjects[index] = { ...newSubjects[index], [field]: field === 'name' ? value : sanitizedValue };

        // Updated calculation: total = mid1 + mid2 + internal + external (Semester end)
        if (['mid1', 'mid2', 'internal', 'external'].includes(field)) {
            newSubjects[index].total = Number(newSubjects[index].mid1) + 
                                       Number(newSubjects[index].mid2) + 
                                       Number(newSubjects[index].internal) + 
                                       Number(newSubjects[index].external);
        }

        setResult({ ...result, subjects: newSubjects });
    };

    const addSubject = () => {
        if (!result) return;
        setResult({
            ...result,
            subjects: [...result.subjects, { code: `SUB-0${result.subjects.length+1}`, name: '', mid1: 0, mid2: 0, internal: 0, external: 0, total: 0, credits: 0 }]
        });
    };

    const removeSubject = (index: number) => {
        if (!result) return;
        setResult({
            ...result,
            subjects: result.subjects.filter((_, i) => i !== index)
        });
    };

    const handleSave = async () => {
        if (!result) return;
        setIsSaving(true);

        // Final calculations before saving
        const totalMarks = result.subjects.reduce((sum, s) => sum + s.total, 0);
        const creditsEarned = result.subjects.reduce((sum, s) => sum + (s.total >= 35 ? 4 : 0), 0);
        const isPass = result.subjects.every(s => s.total >= 35);

        const finalResult: SBTETResult = {
            ...result,
            totalMarks,
            creditsEarned,
            status: isPass ? 'Pass' : 'Fail'
        };

        await saveSbtetResult(finalResult);
        setIsSaving(false);
        alert(`SBTET results for Semester ${semester} saved successfully!`);
    };

    const inputClasses = "w-full p-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded text-sm focus:ring-1 focus:ring-primary-500 outline-none transition-shadow";

    return (
        <Modal isOpen={true} onClose={onClose} title={`Edit SBTET Results: ${student.name}`}>
            <div className="space-y-6 max-h-[80vh] overflow-y-auto pr-2">
                <div className="flex items-center gap-4 border-b dark:border-slate-800 pb-4">
                    <label className="text-sm font-bold">Select Semester:</label>
                    <select 
                        value={semester} 
                        onChange={(e) => setSemester(Number(e.target.value))}
                        className="p-2 bg-white dark:bg-slate-800 border rounded-md"
                    >
                        {[1, 2, 3, 4, 5, 6].map(s => <option key={s} value={s}>Semester {s}</option>)}
                    </select>
                </div>

                {loading ? <p className="animate-pulse">Loading data...</p> : result && (
                    <div className="space-y-4">
                        <div className="grid grid-cols-12 gap-2 text-[10px] font-bold text-slate-500 uppercase px-2 text-center">
                            <div className="col-span-4 text-left">Subject Name</div>
                            <div className="col-span-1.5">Mid 1 (20)</div>
                            <div className="col-span-1.5">Mid 2 (20)</div>
                            <div className="col-span-1.5">Int (20)</div>
                            <div className="col-span-1.5">Sem (40)</div>
                            <div className="col-span-2">Total (100)</div>
                        </div>

                        {result.subjects.map((sub, idx) => (
                            <div key={idx} className="grid grid-cols-12 gap-2 items-center bg-slate-100/50 dark:bg-slate-800/30 p-2 rounded-lg relative group">
                                <div className="col-span-4">
                                    <input 
                                        placeholder="Subject" 
                                        value={sub.name} 
                                        onChange={e => handleSubjectChange(idx, 'name', e.target.value)}
                                        className={inputClasses} 
                                    />
                                </div>
                                <div className="col-span-1.5">
                                    <input 
                                        type="number" 
                                        max={20}
                                        value={sub.mid1} 
                                        onChange={e => handleSubjectChange(idx, 'mid1', e.target.value)}
                                        className={inputClasses} 
                                    />
                                </div>
                                <div className="col-span-1.5">
                                    <input 
                                        type="number" 
                                        max={20}
                                        value={sub.mid2} 
                                        onChange={e => handleSubjectChange(idx, 'mid2', e.target.value)}
                                        className={inputClasses} 
                                    />
                                </div>
                                <div className="col-span-1.5">
                                    <input 
                                        type="number" 
                                        max={20}
                                        value={sub.internal} 
                                        onChange={e => handleSubjectChange(idx, 'internal', e.target.value)}
                                        className={inputClasses} 
                                    />
                                </div>
                                <div className="col-span-1.5">
                                    <input 
                                        type="number" 
                                        max={40}
                                        value={sub.external} 
                                        onChange={e => handleSubjectChange(idx, 'external', e.target.value)}
                                        className={inputClasses} 
                                    />
                                </div>
                                <div className="col-span-2 font-black text-center text-primary-600 text-base">
                                    {sub.total}
                                </div>
                                <button 
                                    onClick={() => removeSubject(idx)} 
                                    className="absolute -right-2 -top-2 bg-red-500 text-white rounded-full w-5 h-5 text-xs opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center"
                                >×</button>
                            </div>
                        ))}

                        <button 
                            onClick={addSubject}
                            className="w-full py-2 border-2 border-dashed border-slate-300 dark:border-slate-700 rounded-lg text-sm text-slate-500 hover:text-primary-500 hover:border-primary-500 transition-colors"
                        >
                            + Add Subject
                        </button>
                    </div>
                )}

                <div className="flex justify-end gap-3 pt-4 sticky bottom-0 bg-white dark:bg-slate-900 pb-2">
                    <button onClick={onClose} className="px-4 py-2 text-sm font-medium rounded-md bg-slate-100 dark:bg-slate-800">Cancel</button>
                    <button 
                        onClick={handleSave} 
                        disabled={isSaving || loading}
                        className="px-6 py-2 text-sm font-medium rounded-md bg-primary-600 text-white hover:bg-primary-700 disabled:opacity-50 shadow-lg"
                    >
                        {isSaving ? 'Saving...' : 'Save Results'}
                    </button>
                </div>
            </div>
        </Modal>
    );
};

