// services.ts
import { Resend } from 'resend';

const resend = new Resend(process.env.RESEND_API_KEY);

interface SendEmailParams {
  to: string;
  subject: string;
  html: string;
}

export const sendEmail = async ({ to, subject, html }: SendEmailParams) => {
  if (!process.env.RESEND_API_KEY) {
    console.warn("Resend API key not configured.  Email not sent.  Ensure RESEND_API_KEY is in your environment variables");
    return {
      status: 'error',
      message: 'Resend API key not configured.',
    };
  }

  try {
    const data = await resend.emails.send({
      from: 'Mira Attendance <noreply@miraattendance.com>', // Replace with your verified sender domain
      to: [to],
      subject,
      html,
    });
    return { status: 'success', data };
  } catch (error) {
    console.error("Failed to send email:", error);
    return { status: 'error', message: (error as Error).message };
  }
};

export const sendLoginOtp = async (email: string, otp: string) => {
  const subject = 'Your Mira Attendance Login OTP';
  const html = `
    <div style="font-family: sans-serif; padding: 20px;">
